class Solution(object):
    def minimizeMax(self, nums, p):
        if p == 0:
            return 0
        nums.sort()
        n = len(nums)

        def can_form_p_pairs(max_diff):
            # Greedy: scan sorted array, greedily pair adjacent elements
            count = 0
            i = 0
            while i < n - 1:
                if nums[i+1] - nums[i] <= max_diff:
                    count += 1
                    i += 2  # use this pair, skip both
                else:
                    i += 1
            return count >= p

        lo, hi = 0, nums[-1] - nums[0]
        while lo < hi:
            mid = (lo + hi) // 2
            if can_form_p_pairs(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
